import{_ as t,o as r,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const y=JSON.parse('{"title":"19. Part Time Employment","description":"","frontmatter":{"title":"19. Part Time Employment","eba":"Allied Health Professionals 2021-2026","topics":["hours","employment"]},"headers":[],"relativePath":"ebas/allied-health/employment/19-part-time-employment.md","filePath":"ebas/allied-health/employment/19-part-time-employment.md"}'),n={name:"ebas/allied-health/employment/19-part-time-employment.md"};function i(s,e,l,p,m,h){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_19-part-time-employment" tabindex="-1">19. Part Time Employment <a class="header-anchor" href="#_19-part-time-employment" aria-label="Permalink to &quot;19. Part Time Employment&quot;">​</a></h1><p><strong>19.1</strong> A part-time Employee is an Employee who:</p><p><strong>(a)</strong> works less than full-time hours of 38 per week (or less than 76 hours in a fortnight) and;</p><p><strong>(b)</strong> has reasonably predictable hours of work.</p><p><strong>19.2</strong> Minimum Engagement The minimum period of engagement of a part-time Employee is three (3) hours per ordinary shift.</p><p><strong>19.3</strong> Pattern of work</p><p><strong>(a)</strong> Before a person commences part-time employment, the Employer and the future</p><p><strong>(i)</strong> a regular pattern of work, specifying at least the hours worked each day;</p><p><strong>(ii)</strong> which days of the week the Employee will work; and</p><p><strong>(iii)</strong> the actual starting and finishing times each day.</p><p><strong>(b)</strong> The Employer will ensure that the Employee’s letter of offer required to be provided in accordance with <a href="/eba/ebas/allied-health/employment/23-letter-of-offer.html">clause 23</a> and <a href="/eba/ebas/allied-health/appendices/5-letter-of-offer.html">Appendix 5</a> includes the agreed information in subclauses 19.3(a)(i) to (iii).</p><p><strong>(c)</strong> Any variation to the regular pattern of work must be by agreement between the Employer and the Employee and will be recorded in writing.</p><p><strong>19.4</strong> Additional Ordinary Hours for Part Time Employees by agreement only</p><p><strong>(a)</strong> A part time Employee cannot be required to work additional ordinary hours except by agreement.</p><p><strong>(b)</strong> An offer of additional hours to a part time Employee at the applicable ordinary time rates for the time worked, must be within the limits prescribed by this Agreement.</p><p><strong>(c)</strong> A part-time Employee is entitled to decline an offer of additional ordinary hours.</p><p><strong>(d)</strong> Where a part-time Employee is directed by the Employer to work reasonable additional hours or works hours in excess of 38 in a week, an average of 38 hours a week or the limits prescribed by the Agreement, overtime rates will apply.</p><p><strong>(e)</strong> In the event of a dispute as to whether a part time Employee agreed to work additional ordinary hours, evidence of that agreement must be in writing, such as an email, text or other electronic message, otherwise the additional hours must be paid as overtime.</p><p><strong>19.5</strong> Part-Time Review of Hours</p><p><strong>(a)</strong> Where over a period of 26 weeks or more a part-time Employee regularly and systematically works more than their contracted hours, the Employer or the Employee may request in writing a contract variation reflecting that the Employee’s hours have increased on a permanent basis (including conversion to a full-time Employee). Such a request will not be unreasonably refused by the Employer.</p><p><strong>(b)</strong> Where the Employer makes the request under subclause 19.5(a), at the time of making the request the Employer will also notify the Employee in writing of their obligations under this subclause 19.5.</p><p><strong>(c)</strong> An Employee will not be considered to be regularly and systematically rostered if the shifts the Employee has been working are replacing an absent Employee (for example parental leave, long service leave, workers’ compensation or personal leave) or a temporary flexible work arrangement.</p><p><strong>(d)</strong> A written response will be provided no later than 21 days from the date of a request (by either an Employee or Employer) If the Employee fails to give the Employer a written response in accordance with this subclause 19.5(d), the Employee is deemed to have provided a response declining the offer.</p><p><strong>(e)</strong> Where the request is refused by the Employer:</p><p><strong>(i)</strong> the written response will include reasons for the refusal;</p><p><strong>(ii)</strong> an Employee may request that the Employer provides any evidence relied upon in making a determination under this subclause 19.5; and</p><p><strong>(iii)</strong> where a dispute arises in relation to the response by the Employer it will be dealt with in accordance with <a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">Clause 14</a> (Dispute Resolution Procedure).</p><p><strong>(f)</strong> Where the request is granted the Employee will be provided with a variation by the Employer setting out the revised employment arrangements reflecting those hours worked on a regular and systematic basis as described in subclauses 19.5(a) and (c) above or as otherwise agreed.</p><p><strong>19.6</strong> Entitlements</p><p>The terms of this Agreement apply to part-time Employees (except where a clause explicitly states that it does not apply to part-time Employees), on the basis that the ordinary weekly hours for full-time Employees are 38, including:</p><p><strong>(a)</strong> payment at an hourly rate equal to 1/38th of the weekly rate appropriate for the Employee’s classification; and</p><p><strong>(b)</strong> accrued paid leave, Family Violence Leave and Professional Development Leave on a pro rata basis, including on any additional ordinary hours.</p><p>Plain language terms: part-time, PT.</p>',33)])])}const g=t(n,[["render",i]]);export{y as __pageData,g as default};
